let currentLang = 'en';

function setLanguage(lang) {
    if (!I18N[lang]) return;
    
    currentLang = lang;
    
    // Update active button
    document.querySelectorAll('.lang-btn').forEach(btn => {
        btn.classList.toggle('active', btn.dataset.lang === lang);
    });
    
    // Update RTL
    document.documentElement.dir = (lang === 'fa' || lang === 'ps') ? 'rtl' : 'ltr';
    document.documentElement.lang = lang;
    
    // Update all elements with data-i18n
    document.querySelectorAll('[data-i18n]').forEach(el => {
        const key = el.dataset.i18n;
        if (I18N[lang][key]) {
            // Handle placeholders like {next}
            let text = I18N[lang][key];
            if (text.includes('{next}')) {
                const nextStep = el.closest('.btn-next')?.dataset.next;
                const nextTexts = {
                    '2': lang === 'fa' ? 'هویت برند' : lang === 'ps' ? 'د نښان پوهه' : 'Brand Identity',
                    '3': lang === 'fa' ? 'بازاریابی' : lang === 'ps' ? 'بازارموندنه' : 'Marketing',
                    '4': lang === 'fa' ? 'تماس' : lang === 'ps' ? 'اړیکه' : 'Contact'
                };
                text = text.replace('{next}', nextTexts[nextStep] || '');
            }
            el.textContent = text;
        }
    });
    
    // Store preference
    localStorage.setItem('maseer_lang', lang);
}

document.addEventListener('DOMContentLoaded', () => {
    // Language switcher
    document.querySelectorAll('.lang-btn').forEach(btn => {
        btn.addEventListener('click', (e) => {
            setLanguage(e.target.dataset.lang);
        });
    });
    
    // Load saved preference or detect browser
    const saved = localStorage.getItem('maseer_lang');
    const browser = navigator.language.slice(0, 2);
    
    if (saved && I18N[saved]) {
        setLanguage(saved);
    } else if (I18N[browser]) {
        setLanguage(browser);
    }
});
